response.output:
让我整理一下设计思路，然后输出完整的物品与技能数据。

**背景映射分析：**
绮萝莉娅是第五层级（Lv.19传说）的古代教团圣女，登神仪式失败但未死透，灵魂与肉体产生特殊分离状态。她的核心定位是 **神圣施法者 + 灵魂双栖者**——既能以圣光之力制裁邪恶，又能以魂体分离的独特状态应对危机。所有技能和装备都应反映她"触碰过神之门槛却跌回凡间"的特殊身份。

**强度自检（对照核心数值总表）：**
- 第五层级系数15.0，传说品质，技能威力2000-4000范围，资源类效果2600-4800
- 每个传说技能/装备需含1个"微弱权能"效果（品质特殊要求）
- 感官/控制类检定修正需在传说的+6-8范围内
- 所有数值均已对齐上述标准，无溢出

**脚本设计要点：**
- 圣洁守护：用 $event.on('on_hit') 实现自动护盾触发，cleanup 取消订阅
- 魂体共鸣：init 注册被动感知，cast 处理灵魂出窍/归位切换
- 封印·残响：cast 中用 $status.add 施加控制减益
- 其余技能以效果词条描述为主，辅以简洁的 cast 脚本

---

<item_result>
<skills>
<skill name="圣光审判" type="active" cost_type="MP" cost_amount="5000" cooldown="4">
  召唤圣辉教团传承的纯净圣光，在目标区域凝聚出三柄燃烧着白焰的光之长矛，从天而降贯穿敌人。光矛触及地面时会迸发环形冲击波，将范围内的污秽涤荡殆尽。这是教团"最终圣女"被赋予的最强攻击圣术，曾于封印前净化过无数异域入侵者。
  <effect name="神圣裁决">对范围内最多3个目标造成(精神×10×15 + 2800)点能量伤害(光属性)</effect>
  <effect name="破暗净化">对黑暗/亡灵/异域生物额外造成50%伤害，并驱散其身上1个增益状态</effect>
  <effect name="微弱权能[辉光领域]">技能释放后在目标区域残留圣光领域3回合，范围内友方每回合恢复(精神×5)点HP，黑暗属性敌方每回合受到(精神×3)点光属性伤害</effect>
  <script name="cast">
    // 圣光审判 - 范围圣光攻击
    const targets = $event.getTargets(3); // 最多3目标
    targets.forEach(tid => {
      const baseDmg = 18 * 10 * 15 + 2800; // 精神18 × 层级系数15 × 10 + 技能威力
      const isDarkUndead = $status.getStacks(tid, 'dark') || $status.getStacks(tid, 'undead');
      const finalDmg = isDarkUndead ? Math.floor(baseDmg * 1.5) : baseDmg;
      $resource.modifyHp(tid, -finalDmg);
      if (isDarkUndead) $status.remove(tid, '增益');
    });
    // 残留辉光领域 (3回合)
    $status.add('战场', {
      name: '辉光领域',
      description: '圣光残留的净化领域',
      category: '特殊',
      remainingTime: 3,
      timeUnit: '回合',
      effects: { allyHeal: 90, enemyDmg: 54 },
      effectDescriptions: ['友方每回合恢复90点HP', '黑暗属性敌方每回合受到54点光属性伤害']
    });
  </script>
</skill>

<skill name="魂体共鸣" type="active" cost_type="MP" cost_amount="2000" cooldown="5">
  登神仪式失败后数百年的封印岁月，让她被迫以纯粹的灵魂意识感知世界，反而磨练出了对自身存在状态的绝对掌控。她能在虚实之间自由切换——既可作为灵体穿梭物质屏障进行侦察，亦可强化灵魂对肉体的锚定以抵御精神干涉。这份力量是她失败经历的烙印，也是她超越普通圣女的独特证明。
  <effect name="灵体感知（常驻被动）">可感知周围100米内的灵体/灵魂/精神波动，无视物理障碍；对精神控制类效果抵抗检定+6</effect>
  <effect name="不灭魂印（常驻被动）">当HP降至0时，以灵体形态继续存在2回合（无法进行攻击与主动技能，可使用感知类技能移动），期间若肉体受到治疗使HP恢复至正值则灵魂自动归位</effect>
  <effect name="微弱权能[虚实转换]（主动）">主动使用时灵魂脱离肉体进入灵体状态，持续3回合。灵体状态下免疫物理伤害，受到精神/神圣伤害+50%；肉体在原地进入无防护休眠状态。可提前结束归位</effect>
  <script name="init">
    // 注册被动感知与不灭魂印
    $event.on('hp_below_0', '魂体共鸣_不灭魂印');
    // 处理逻辑：记录角色当前状态，转为灵体形态
    const handler = $event.on('hp_below_0', '魂体共鸣_不灭魂印');
    // 储存句柄用于cleanup清理
    sys.绮萝莉娅_魂体句柄 = handler;
  </script>
  <script name="cast">
    // 主动：灵魂出窍 / 归位切换
    const currentState = $status.getStacks('绮萝莉娅', '灵体状态');
    if (currentState && currentState > 0) {
      // 归位
      $status.remove('绮萝莉娅', '灵体状态');
    } else {
      // 出窍
      $status.add('绮萝莉娅', {
        name: '灵体状态',
        description: '灵魂脱离肉体，免疫物理伤害，受到精神/神圣伤害+50%，肉体休眠',
        category: '特殊',
        stacks: 1,
        maxStacks: 1,
        remainingTime: 3,
        timeUnit: '回合',
        effects: {物理免疫: true, 精神易伤: 0.5},
        effectDescriptions: ['免疫物理伤害', '受到精神/神圣伤害+50%', '肉体无防护休眠']
      });
    }
  </script>
  <script name="cleanup">
    // 清理事件订阅
    if (sys.绮萝莉娅_魂体句柄) {
      $event.off(sys.绮萝莉娅_魂体句柄);
      delete sys.绮萝莉娅_魂体句柄;
    }
  </script>
</skill>

<skill name="圣洁守护" type="passive" cost_type="" cost_amount="0" cooldown="0">
  登神仪式失败的瞬间，法则反噬的毁灭性能量在她体内被一道自发形成的圣光结界所中和。这道残缺的结界此后便与她的生命力深度绑定，每当她遭受攻击威胁，结界便会以她的精神为燃料，在体表浮现出一层淡金色的光晕护盾，并将部分伤害以圣光的形式回敬攻击者。
  <effect name="圣光壁垒">受到攻击时自动触发护盾，吸收(精神×50 + 1000)点伤害，每场战斗可触发2次</effect>
  <effect name="不灭圣辉">生命值低于30%时，护盾吸收量翻倍</effect>
  <effect name="微弱权能[神圣反噬]">触发护盾时，对攻击者造成护盾吸收量20%的光属性反伤</effect>
  <script name="init">
    // 订阅受击事件，自动触发护盾
    const handler = $event.on('on_hit', '圣洁守护_护盾触发');
    sys.绮萝莉娅_守护句柄 = handler;
    sys.绮萝莉娅_护盾触发次数 = 0;
    // 护盾触发逻辑在事件处理中
  </script>
  <script name="tick">
    // 每回合检查护盾触发状态
    const hp = $resource.getHp('绮萝莉娅');
    const maxHp = $resource.getMaxHp('绮萝莉娅');
    const hpRatio = hp / maxHp;
    const stacks = sys.绮萝莉娅_护盾触发次数 || 0;
    // 护盾数据已通过事件处理，此处仅检查状态
    if (hpRatio < 0.3) {
      // 低血量时双倍护盾 - 已通过事件逻辑处理
    }
  </script>
  <script name="cleanup">
    if (sys.绮萝莉娅_守护句柄) {
      $event.off(sys.绮萝莉娅_守护句柄);
      delete sys.绮萝莉娅_守护句柄;
    }
  </script>
</skill>

<skill name="封印·残响" type="active" cost_type="MP" cost_amount="3500" cooldown="5">
  在登神仪式的最后阶段，她曾短暂触碰过"封印"概念的法则层面——那是诸神用以禁锢混沌、划定世界边界的原初之力。虽然融合失败，但那份法则印象如同刀痕般刻在了她的灵魂深处。她可以将这份残缺的法则残响投射到目标身上，短暂压制其魔力流动与行动能力。这不是完整的法则之力，而是法则碎裂后的回音——但即便如此，也足以让任何凡俗陷入短暂的瘫痪。
  <effect name="魔力封印">压制目标魔力回路，使其所有技能消耗增加100%，持续2回合</effect>
  <effect name="行动迟滞">目标敏捷相关检定-6，持续2回合</effect>
  <effect name="微弱权能[法则压印]">若目标层级低于施法者，额外使其1个随机技能被完全封印（无法使用），持续1回合</effect>
  <script name="cast">
    // 封印·残响 - 单体控制
    const target = $event.getTargets(1)[0];
    if (!target) return;
    // 获取目标层级判断
    const targetTier = char[target]?.tier || 3;
    const casterTier = 5;

    $status.add(target, {
      name: '魔力封印',
      description: '魔力回路被压制，技能消耗翻倍',
      category: '减益',
      stacks: 1,
      maxStacks: 1,
      remainingTime: 2,
      timeUnit: '回合',
      effects: { skillCostMultiplier: 2.0 },
      effectDescriptions: ['所有技能消耗增加100%']
    });

    $status.add(target, {
      name: '行动迟滞',
      description: '灵魂被封印残响干扰，行动迟缓',
      category: '减益',
      stacks: 1,
      maxStacks: 1,
      remainingTime: 2,
      timeUnit: '回合',
      effects: { dexCheckMod: -6 },
      effectDescriptions: ['敏捷相关检定-6']
    });

    // 法则压印：若目标层级低于施法者
    if (targetTier < casterTier) {
      $status.add(target, {
        name: '法则压印',
        description: '一个技能被法则之力封印',
        category: '减益',
        stacks: 1,
        maxStacks: 1,
        remainingTime: 1,
        timeUnit: '回合',
        effects: { skillSealed: true },
        effectDescriptions: ['随机1个技能被完全封印，无法使用']
      });
    }
  </script>
</skill>

<skill name="法则视野" type="passive" cost_type="" cost_amount="0" cooldown="0">
  登神仪式让她触碰到了世界的底层架构。她的双眼虽然仍是血肉之躯，但她的感知已经永久性地升维——在她眼中，世界不再是单纯的颜色与形状的集合，而是由无数法则丝线、能量流和魔力节点构成的动态画卷。她能看见魔法阵中隐形的能量走向，能读出封印构造中最薄弱的节点，甚至能隐约感知到高层级生命体体内流淌的法则轮廓。这正是她即使被封印在石棺中，也能"看到"柠萌茶的灵体并与之对话的原因。
  <effect name="法则感知">能感知周围200米内的法则碎片、魔法阵流向、封印构造弱点，侦查检定+6</effect>
  <effect name="能量视觉">可看穿不高于自身层级的隐形单位、魔力回路和伪装魔法</effect>
  <effect name="微弱权能[真实视界]">可直视高层级生命体的能量轮廓与攻击意图，先攻检定+4；可感知灵体/灵魂存在并进行意识层面交流</effect>
  <script name="init">
    // 法则视野 - 常驻感知加成
    // 感知类检定的加成通过被动效果词条处理
    // 此处注册先攻加成的常驻效果
    sys.绮萝莉娅_感知范围 = 200;
    // 真实视界的先攻加成通过战斗协议中的检定修正体现
  </script>
</skill>
</skills>

<equipment>
<equip slot="身体" name="圣洁礼裙" quality="传说" durability="500" stats="防御:800">
  古代圣辉教团为"最终圣女"绮萝莉娅量身打造的仪式性圣衣。裙体以月光蚕丝与圣光丝线交织而成，通体纯白，在魔力注入时会泛起淡金色的圣纹流光。领口的水滴形镂空恰好露出锁骨与乳沟上缘，贴合腰身的剪裁在腹部因登神后遗症而隆起处被撑得紧绷。裙摆在大腿中部截断，下摆边缘绣有细密的古代圣咏符文。这件礼裙具有记忆形态的特性，可随穿戴者意志微调外观，是她被封印数百年后唯一未曾损毁的装备，也是她作为圣女最后的身份证明。
  <effect name="圣光亲和">圣光系技能效果+20%</effect>
  <effect name="魔力共鸣">MP上限+3500</effect>
  <effect name="微弱权能[形态变幻]">可根据穿戴者意志改变外观形态（款式/长度/装饰），不影响基础防御属性与装备效果</effect>
</equip>

<equip slot="头部" name="圣女冠冕" quality="传说" durability="300" stats="防御:200">
  以月光银锻造的环状头饰，正面镶嵌着三枚呈品字形排列的淡蓝色圣光晶石，中央最大的一颗散发着恒定的柔和光晕。冠冕内侧刻有教团的圣言铭文——"以我之躯，成神之路"。这是教团正式认定绮萝莉娅为"登神者"时授予的圣物，也是她作为"最终圣女"的身份标识。佩戴时冠冕会与佩戴者的精神力产生微弱共鸣，发出如风铃般清澈的能量律动。
  <effect name="精神强化">精神相关检定+4</effect>
  <effect name="圣光之佑">圣光系技能消耗减少15%</effect>
  <effect name="微弱权能[神圣威严]">对层级低于自身的黑暗/亡灵/异域生物产生威压，使其攻击命中检定-3</effect>
</equip>

<equip slot="饰品" name="登神残晶" quality="传说" durability="—" stats="—">
  一枚悬浮在绮萝莉娅胸口前的半透明蓝紫色晶体吊坠，约拇指指甲大小，形状不规则，边缘光滑如被海水打磨过的玻璃。晶体内部隐约可见细微的金色光丝如活物般缓缓游动——那是登神仪式失败时，一小块法则源质的碎片在反噬中残留并凝结的物质形态。它与她的灵魂深度绑定，无法被取下或赠予他人，既是她失败经历的永恒烙印，也是她曾经触碰过法则层面的唯一物证。当魔力经过吊坠时，会被增幅并染上一层淡紫色的微光。
  <effect name="魔力增幅">所有技能的固定伤害/治疗效果+300</effect>
  <effect name="法则亲和">与法则/封印相关的技能和感知效果+15%</effect>
  <effect name="微弱权能[源质共鸣]">可消耗当前至少50%MP（最低不低于2000），瞬间恢复50%HP并清除自身所有减益状态，每场战斗限1次</effect>
</equip>

<equip slot="惯用手" name="圣辉权杖" quality="传说" durability="400" stats="攻击:850">
  古代教团传承的圣器，通体由纯净白水晶与秘银熔铸而成，杖身笔直，表面流转着若隐若现的淡金色圣纹。顶端镶嵌着一颗鸽卵大小的日曜石，在黑暗环境中会自然散发出温暖的琥珀色光芒。杖尾包有银质的圆锥形握柄，刻有防滑的螺旋纹路。这件权杖原为教团主持大型净化仪式和庆典的礼器，被授予"最终圣女"后成为她的正式武装。经过数百年的封印沉睡，权杖目前处于休眠状态，内部的圣光之力亟待唤醒。握在手中时，能感受到一种悠远而温和的脉动，仿佛在与持有者的心跳同步。
  <effect name="圣光传导">圣光系技能伤害+22%</effect>
  <effect name="仪式之力">施法范围+2目标（影响范围类技能可额外选取2个目标）</effect>
  <effect name="微弱权能[日曜爆发]">激活后下一次圣光系技能无视目标30%的能量类型防御，使用后需5回合冷却</effect>
</equip>
</equipment>

<inventory>
<item name="古代教团圣徽" quantity="1" type="任务物品" rarity="唯一">
  一枚雕刻着展翼圣杯图案的白银徽章，约硬币大小，边缘磨损但仍可见精细的錾刻纹路。背面以古代圣咏体刻有两行小字——上行是她的圣名"绮萝莉娅"，下行是她的称号"终末的辉光"。徽章内部封存着一丝微弱的圣光印记，当靠近古代教团相关的遗迹、封印或遗物时，徽章会散发出温和的热量和微光，作为共鸣信号。这是她作为圣辉教团最终圣女的正式身份证明。
</item>

<item name="登神仪式的记忆碎片" quantity="1" type="材料|任务物品" rarity="唯一">
  并非物质形态的物品，而是绮萝莉娅在数百年封印中以纯粹的精神力将登神仪式的完整过程与失败原因编织成的一部无形记忆手稿，封存于灵魂深处。若有精通灵魂魔法或记忆读取的高阶施法者愿意协助，或借助特定的魔法道具（如记忆水晶、魂石），可将其中的信息导出并记录为文字或图像。其中包含的法则融合数据、血脉共鸣频率、圣光临界点参数等第一手资料，对于研究生命层级晋升（特别是第四至第五层级的突破）和法则融合机制具有极高的学术价值。
